__device__ void calculate_micro_xs(   double p_energy, int nuc, long n_isotopes,
                           long n_gridpoints,
                           double * __restrict__ egrid, int * __restrict__ index_data,
                           NuclideGridPoint * __restrict__ nuclide_grids,
                           long idx, double * __restrict__ xs_vector, int grid_type, int hash_bins )
{
    // ...

    // calculate the re-useable interpolation factor
    double interpolation_factor = (high->energy - p_energy) / (high->energy - low->energy);

    // Total XS
    xs_vector[0] = high->total_xs - interpolation_factor * (high->total_xs - low->total_xs);

    // Elastic XS
    xs_vector[1] = high->elastic_xs - interpolation_factor * (high->elastic_xs - low->elastic_xs);

    // Absorbtion XS
    xs_vector[2] = high->absorbtion_xs - interpolation_factor * (high->absorbtion_xs - low->absorbtion_xs);

    // Fission XS
    xs_vector[3] = high->fission_xs - interpolation_factor * (high->fission_xs - low->fission_xs);

    // Nu Fission XS
    xs_vector[4] = high->nu_fission_xs - interpolation_factor * (high->nu_fission_xs - low->nu_fission_xs);

    // ...
}
